// Orders is the resolver for the orders field.
func (r *queryResolver) Orders(ctx context.Context, branchID uuid.UUID, status *model.OrderStatus, limit *int) ([]model.Order, error) {
	orders, err := r.Services.Order.GetByBranch(ctx, branchID)
	if err != nil {
		return nil, err
	}
	if status != nil {
		filtered := make([]model.Order, 0)
		for _, o := range orders {
			if o.Status == *status {
				filtered = append(filtered, o)
			}
		}
		orders = filtered
	}
	if limit != nil && len(orders) > *limit {
		orders = orders[:*limit]
	}
	return orders, nil
}

