// DashboardMetrics is the resolver for the dashboardMetrics field.
func (r *queryResolver) DashboardMetrics(ctx context.Context, branchID uuid.UUID, period string) (*DashboardMetrics, error) {
	metrics, err := r.Services.Analytics.GetDashboardMetrics(ctx, branchID)
	if err != nil {
		return nil, err
	}

	topProds, err := r.Services.Analytics.GetTopProducts(ctx, branchID, 10)
	if err != nil {
		topProds = []TopProduct{}
	}

	var topProducts []TopProduct
	for _, p := range topProds {
		topProducts = append(topProducts, TopProduct{
			ProductID:    p.ProductID,
			ProductName:  p.ProductName,
			QuantitySold: p.QuantitySold,
			Revenue:      p.Revenue,
		})
	}

	// Get sales by day for the last 7 days
	dailySales, _ := r.Services.Analytics.GetSalesByDay(ctx, branchID, 7)
	var dailySalesResult []DailySales
	for _, ds := range dailySales {
		dailySalesResult = append(dailySalesResult, DailySales{
			Date:    ds.Date,
			Revenue: ds.Revenue,
			Orders:  ds.Orders,
		})
	}

	return &DashboardMetrics{
		TotalRevenue:     metrics.TotalRevenue,
		TodayRevenue:     metrics.TodayRevenue,
		WeekRevenue:      metrics.WeekRevenue,
		MonthRevenue:     metrics.MonthRevenue,
		TotalOrders:      metrics.TotalOrders,
		OrdersToday:      metrics.OrdersToday,
		OrdersThisWeek:   metrics.OrdersThisWeek,
		OrdersThisMonth:  metrics.OrdersThisMonth,
		AverageTicket:    metrics.AverageTicket,
		ActiveOrders:     metrics.ActiveOrders,
		TotalTables:      metrics.TotalTables,
		AvailableTables: metrics.AvailableTables,
		TopProducts:      topProducts,
		DailySales:       dailySalesResult,
	}, nil
}

