// ============ Helper Functions ============

// convertTablesToGraphQL converts model.RestaurantTable to graph.Table
func convertTablesToGraphQL(tables []model.RestaurantTable, err error) ([]Table, error) {
	if err != nil {
		return nil, err
	}
	result := make([]Table, len(tables))
	for i, t := range tables {
		result[i] = Table{
			ID:        t.ID,
			BranchID:  t.BranchID,
			Number:    t.Number,
			Capacity:  t.Capacity,
			Status:    t.Status,
			CreatedAt: t.CreatedAt,
			UpdatedAt: t.UpdatedAt,
		}
	}
	return result, nil
}

// serviceCreateProductInput converts CreateProductInput to service.CreateProductInput
func serviceCreateProductInput(input CreateProductInput) service.CreateProductInput {
	result := service.CreateProductInput{
		BranchID:  input.BranchID,
		Name:      input.Name,
		Price:     input.Price,
		Allergens: []string{},
	}
	if input.CategoryID != nil {
		result.CategoryID = input.CategoryID
	}
	if input.Description != nil {
		result.Description = input.Description
	}
	if input.ImageURL != nil {
		result.ImageURL = input.ImageURL
	}
	if input.IsAvailable != nil {
		result.IsAvailable = input.IsAvailable
	}
	if input.IsFeatured != nil {
		result.IsFeatured = input.IsFeatured
	}
	if input.PreparationTime != nil {
		result.PreparationTime = input.PreparationTime
	}
	if input.Allergens != nil {
		result.Allergens = input.Allergens
	}
	return result
}

// serviceReservationInput converts CreateReservationInput to service.CreateReservationInput
func serviceReservationInput(input CreateReservationInput) service.CreateReservationInput {
	result := service.CreateReservationInput{
		BranchID:    input.BranchID,
		CustomerName: input.CustomerName,
		GuestCount:  input.GuestCount,
		ReservationDate: input.ReservationDate.Format("2006-01-02"),
		ReservationTime: input.ReservationTime,
	}
	if input.TableID != nil {
		result.TableID = input.TableID
	}
	if input.CustomerPhone != nil {
		result.CustomerPhone = input.CustomerPhone
	}
	if input.CustomerEmail != nil {
		result.CustomerEmail = input.CustomerEmail
	}
	if input.Notes != nil {
		result.Notes = input.Notes
	}
	return result
}
